202	static std::mutex _usrp_find_mutex;
203	uhd_error uhd_usrp_find(const char* args, uhd_string_vector_handle* strings_out)
204	{
205	    UHD_SAFE_C(
206	        std::lock_guard<std::mutex> _lock(_usrp_find_mutex);
207	
208	        uhd::device_addrs_t devs =
209	            uhd::device::find(std::string(args), uhd::device::USRP);
210	        (*strings_out)->string_vector_cpp.clear();
211	        for (const uhd::device_addr_t& dev
212	             : devs) { (*strings_out)->string_vector_cpp.push_back(dev.to_string()); })
213	}
