215	static std::mutex _usrp_make_mutex;
216	uhd_error uhd_usrp_make(uhd_usrp_handle* h, const char* args)
217	{
218	    UHD_SAFE_C(std::lock_guard<std::mutex> lock(_usrp_make_mutex);
219	
220	               size_t usrp_count = usrp_ptr::usrp_counter;
221	               usrp_ptr::usrp_counter++;
222	
223	               // Initialize USRP
224	               uhd::device_addr_t device_addr(args);
225	               usrp_ptr P;
226	               P.ptr = uhd::usrp::multi_usrp::make(device_addr);
227	
228	               // Dump into registry
229	               get_usrp_ptrs()[usrp_count] = P;
230	
231	               // Update handle
232	               (*h)             = new uhd_usrp;
233	               (*h)->usrp_index = usrp_count;)
234	}
235	
236	static std::mutex _usrp_free_mutex;
237	uhd_error uhd_usrp_free(uhd_usrp_handle* h)
238	{
239	    UHD_SAFE_C(
240	        std::lock_guard<std::mutex> lock(_usrp_free_mutex);
241	
242	        if (!get_usrp_ptrs().count((*h)->usrp_index)) { return UHD_ERROR_INVALID_DEVICE; }
243	
244	        get_usrp_ptrs()
245	            .erase((*h)->usrp_index);
246	        delete *h;
247	        *h = NULL;)
248	}
