}

uhd_error uhd_usrp_set_gpio_attr(uhd_usrp_handle h,
    const char* bank,
    const char* attr,
    uint32_t value,
    uint32_t mask,
    size_t mboard)
{
    UHD_SAFE_C_SAVE_ERROR(h,
                          USRP(h)->set_gpio_attr(
                              std::string(bank), std::string(attr), value, mask, mboard);)
}

uhd_error uhd_usrp_get_gpio_attr(uhd_usrp_handle h,
    const char* bank,
    const char* attr,
    size_t mboard,
    uint32_t* attr_out)
{
    UHD_SAFE_C_SAVE_ERROR(
        h,
        *attr_out = USRP(h)->get_gpio_attr(std::string(bank), std::string(attr), mboard);)
}

